97	float get_flops_promised(const char* device, int precision_mode) {
98	    /*
99	    This function is used to estimate the Model Flops Utilization (MFU)
100	    basically we have to figure out how many flops the GPU can do per second.
101	    Note that this is not a simple endeavor and may well go wrong! The details are tricky.
102	    The returned value is in units of 1e12.
103	
104	    For the non-top models, actual performance numbers aren't that easy to find, e.g.,
105	    here https://www.techpowerup.com/gpu-specs/rtx-a4000.c3756, does "Theoretical Performance"
106	    seems to be without tensor cores.
107	
108	    So, instead we use that all these cards just use the same types of tensor cores in different
109	    numbers and at different frequencies. Then we just need to look up these two easily accesible
110	    numbers for all the other GPUs.
111	    linear scaling seems to work: comparing spec sheet and calculation:
112	    4080: 304TCs, 2505 GHz; 97.5TFlops = 165.2/512*304 /2520 * 2505
113	
114	    Original numbers for the top GPUS are from.
115	    https://resources.nvidia.com/en-us-tensor-core
116	    https://images.nvidia.com/aem-dam/Solutions/geforce/ada/nvidia-ada-gpu-architecture.pdf
117	    */
118	
119	   // validate the precision mode as one of the three possible values
120	    if (!(precision_mode == MFUH_PRECISION_FP32 || precision_mode == MFUH_PRECISION_FP16 || precision_mode == MFUH_PRECISION_BF16)) {
121	        fprintf(stderr, "Invalid precision mode: %d\n", precision_mode);
122	        return -1.0f;
123	    }
124	
125	    // do a linear search until you find our GPU, then calculate the flops promised
126	    int num_gpu_entries = sizeof(gpu_db) / sizeof(gpu_db[0]);
127	    for (int i = 0; i < num_gpu_entries; i++) {
128	        if (strcmp(gpu_db[i].name, device) == 0) {
129	            const PerfData* perf_data = gpu_db[i].perf_data;
130	
131	            // look up the default flops value for the given precision mode
132	            float value = -1.0f;
133	            if (precision_mode == MFUH_PRECISION_BF16) { value = perf_data->BF_16_32; }
134	            if (precision_mode == MFUH_PRECISION_FP32) { value = perf_data->TF_32; }
135	            if (precision_mode == MFUH_PRECISION_FP16) { value = perf_data->FP_16_32; }
136	
137	            // we'd get here if we're e.g. trying to use BF16 on Volta GPU or something...
138	            if (value < 0.0f) {
139	                fprintf(stderr, "No data for GPU %s and precision mode %d\n", device, precision_mode);
140	                return -1.0f;
141	            }
142	
143	            // adjust flops based on the specific core count and clock frequency of this GPU
144	            float new_cores = gpu_db[i].new_cores;
145	            float new_mhz = gpu_db[i].new_mhz;
146	            float adjusted = value * (new_cores / perf_data->CORES) * (new_mhz / perf_data->CLOCK);
147	            return adjusted;
148	        }
149	    }
150	
151	    return -1.0f; // ¯\_(ツ)_/¯
152	}
