154	struct GPUUtilInfo {
155	    unsigned int clock;
156	    unsigned int max_clock;
157	    unsigned int power;
158	    unsigned int power_limit;
159	    unsigned int fan;
160	    unsigned int temperature;
161	    unsigned int temp_slowdown;
162	
163	    float gpu_utilization;
164	    float mem_utilization;
165	    const char* throttle_reason;
166	};
167	
168	// lazily initialize nvml and generate a handle to the GPU
169	#if USE_NVML
170	nvmlDevice_t nvml_get_device() {
171	    static bool needs_init = true;
172	    static nvmlDevice_t device;
173	    if(needs_init) {
174	        needs_init = false;
175	        nvmlCheck(nvmlInit());
176	        nvmlCheck(nvmlDeviceGetHandleByIndex_v2(0, &device));
177	    }
178	    return device;
179	}
180	
181	// convert throttle reason bitfield into a text reason.
182	// this is a lossy conversion; we just want to give some idea of what is happening
183	const char* get_throttle_reason(unsigned long long bits) {
184	    if(bits & (nvmlClocksThrottleReasonSwPowerCap | nvmlClocksThrottleReasonHwPowerBrakeSlowdown)) {
185	        return "power cap";
186	    } else if (bits & (nvmlClocksThrottleReasonSwThermalSlowdown | nvmlClocksThrottleReasonHwThermalSlowdown)) {
187	        return "thermal cap";
188	    } else if (bits & (nvmlClocksThrottleReasonAll)) {
189	        return "other cap";
190	    } else {
191	        return "no cap";
192	    }
193	}
194	
195	// gather data for a GPUUtilInfo object
196	GPUUtilInfo get_gpu_utilization_info() {
197	    GPUUtilInfo info;
198	    nvmlDevice_t device = nvml_get_device();
199	    // query different infos directly
200	    nvmlCheck(nvmlDeviceGetClockInfo(device, NVML_CLOCK_SM, &info.clock));
201	    nvmlCheck(nvmlDeviceGetMaxClockInfo(device, NVML_CLOCK_SM, &info.max_clock));
202	    nvmlCheck(nvmlDeviceGetPowerManagementLimit(device, &info.power_limit));
203	    nvmlCheck(nvmlDeviceGetPowerUsage(device, &info.power));
204	    nvmlCheck(nvmlDeviceGetTemperature(device, NVML_TEMPERATURE_GPU, &info.temperature));
205	    nvmlCheck(nvmlDeviceGetTemperatureThreshold(device, NVML_TEMPERATURE_THRESHOLD_SLOWDOWN, &info.temp_slowdown));
206	    unsigned long long throttle;
207	    nvmlCheck(nvmlDeviceGetCurrentClocksThrottleReasons(device, &throttle));
208	    info.throttle_reason = get_throttle_reason(throttle);
209	    nvmlCheck(nvmlDeviceGetFanSpeed(device, &info.fan));
210	
211	    // for "utilization", we look at recorded samples. In principle, we could query the driver for how many samples
212	    // to request, but then we'd need to dynamically allocate sufficient space. Let's just hard-code a limit of 128,
213	    // and have no memory management required
214	    constexpr const int BUFFER_LIMIT = 128;
215	    nvmlSample_t buffer[BUFFER_LIMIT];
216	    nvmlValueType_t v_type;
217	    unsigned int sample_count = BUFFER_LIMIT;
218	    nvmlCheck(nvmlDeviceGetSamples(device, NVML_GPU_UTILIZATION_SAMPLES, 0, &v_type, &sample_count, buffer));
219	    float gpu_utilization = 0.f;
220	    for(unsigned i = 0; i < sample_count; ++i) {
221	        gpu_utilization += (float)buffer[i].sampleValue.uiVal;
222	    }
223	    gpu_utilization /= (float)sample_count;
224	
225	    // sample count may have been modified by the query above; reset back to buffer size
226	    sample_count = BUFFER_LIMIT;
227	    nvmlCheck(nvmlDeviceGetSamples(device, NVML_MEMORY_UTILIZATION_SAMPLES, 0, &v_type, &sample_count, buffer));
228	    float mem_utilization = 0.f;
229	    for(unsigned i = 0; i < sample_count; ++i) {
230	        mem_utilization += (float)buffer[i].sampleValue.uiVal;
231	    }
232	    mem_utilization /= (float)sample_count;
233	
234	    info.gpu_utilization = gpu_utilization;
235	    info.mem_utilization = mem_utilization;
236	    return info;
237	}
238	#else
239	GPUUtilInfo get_gpu_utilization_info() {
240	    fprintf(stderr, "Error: Compiled without nvml support. Cannot perform additional GPU state tracking.");
241	    exit(EXIT_FAILURE);
242	}
243	#endif
244	#endif // MFU_H
